            {name: "犬犬果实·大口真神形态", desc: "幻兽种，火焰狼神"},
            {name: "鸟鸟果实·不死鸟形态", desc: "幻兽种，再生火焰"},
            {name: "蛇蛇果实·八岐大蛇形态", desc: "幻兽种，八头巨蛇"},
            {name: "猫猫果实·豹形态", desc: "古代种，速度与力量"},
            {name: "象象果实·猛犸象形态", desc: "古代种，巨大力量"},
            {name: "龙龙果实·棘背龙形态", desc: "古代种，恐龙之力"}
        ]
    };

    /* --- 系统状态 --- */
    let maxPoints = 0;
    let currentChapter = 1;
    let usedPoints = 0;
    let selectedFruit = null;

    /* --- 初始化 --- */
    window.onload = function() {
        initChapters();
        resetSystem();
        bindEvents();
    };

    function bindEvents() {
        document.querySelectorAll('.stat').forEach(el => {
            el.addEventListener('input', updatePoints);
        });

        document.getElementById('bounty').addEventListener('input', function() {
            const val = parseInt(this.value) || 0;
            document.getElementById('bountyDisplay').innerText = '₿ ' + val.toLocaleString();
        });
    }

    function resetSystem() {
        // 1. 随机名言
        document.querySelector('#randomQuote strong').innerText = quotes[Math.floor(Math.random() * quotes.length)];

        // 2. 确定天命点数范围
        // 检查是否开启强运模式
        const strongLuck = document.getElementById('strongLuckMode').checked;

        if (strongLuck) {
            // 强运模式：0 - 90 (大起大落)
            maxPoints = Math.floor(Math.random() * 91);
        } else {
            // 默认模式：20 - 50 (更符合新人设定)
            maxPoints = Math.floor(Math.random() * (50 - 20 + 1)) + 20;
        }

        // 动画效果显示数字
        const display = document.getElementById('maxPointsDisplay');
        let i = 0;
        const interval = setInterval(() => {
            display.innerText = Math.floor(Math.random() * 90);
            i++;
            if(i > 10) {
                clearInterval(interval);
                display.innerText = maxPoints;
                updatePoints();
            }
        }, 50);

        // 重置输入
        document.querySelectorAll('.stat').forEach(el => el.value = 0);
        document.getElementById('fruitName').value = "";
        document.getElementById('bounty').value = "";
        document.getElementById('bountyDisplay').innerText = '₿ 0';
        selectedFruit = null;
        updateStatCaps();
    }

    function initChapters() {
        const grid = document.getElementById('chapterList');
        grid.innerHTML = "";
        chapters.forEach(ch => {
            const div = document.createElement('div');
            div.className = `chapter-card ${ch.id === 1 ? 'selected' : ''}`;
            div.innerHTML = `<strong>Chapter ${ch.id}</strong><div>${ch.title}</div>`;
            div.onclick = () => selectChapter(ch.id, div);
            grid.appendChild(div);
        });
    }

    function selectChapter(id, el) {
        currentChapter = id;
        document.querySelectorAll('.chapter-card').forEach(c => c.classList.remove('selected'));
        el.classList.add('selected');
    }

    function updateStatCaps() {
        const hasFruit = document.getElementById('hasFruit').value === "true";
        const fruitInputs = document.querySelectorAll('.fruit-input');
        const fruitDetails = document.getElementById('fruitDetails');

        // 显隐果实详情
        fruitDetails.style.display = hasFruit ? "block" : "none";

        // 更新霸气上限
        const hakiLimit = hasFruit ? 10 : 20;
        ['armament', 'observation', 'conqueror'].forEach(id => {
            const el = document.getElementById(id);
            if(el) {
                el.max = hakiLimit;
                if(parseInt(el.value) > hakiLimit) el.value = hakiLimit;
            }
        });

        // 启用/禁用果实滑块
        fruitInputs.forEach(el => {
            el.disabled = !hasFruit;
            if(!hasFruit) el.value = 0;
            el.parentElement.style.opacity = hasFruit ? 1 : 0.5;
        });

        updatePoints();
    }

    function updatePoints() {
        let total = 0;
        document.querySelectorAll('.stat').forEach(el => {
            let val = parseInt(el.value);
            const span = document.getElementById('val_' + el.id);
            if(span) span.innerText = val;
            total += val;
        });

        const remain = maxPoints - total;
        const remainEl = document.getElementById('pointsRemaining');
        remainEl.innerText = `剩余可用点数：${remain}`;

        if(remain < 0) {
            remainEl.style.color = "red";
            remainEl.innerText += " (已超支！无法生成)";
        } else {
            remainEl.style.color = "var(--ocean-blue)";
        }
        usedPoints = total;
    }

    function toggleNSFW() {
        const el = document.getElementById('nsfwOptions');
        el.style.display = el.style.display === "none" ? "block" : "none";
    }

    function updateGenderEffects() {
        const gender = document.getElementById('gender').value;
        const nsfwToggle = document.querySelector('.nsfw-toggle');

        // 女性角色时自动显示NSFW选项提示
        if(gender === "女") {
