        const randomType = types[Math.floor(Math.random() * types.length)];
        const fruits = devilFruits[randomType];
        const randomFruit = fruits[Math.floor(Math.random() * fruits.length)];

        selectedFruit = {
            type: typeNames[randomType],
            ...randomFruit
