        const concept = document.getElementById('originalFruitConcept').value;
        if(!concept) {
            alert('请先输入果实能力概念！');
            return;
        }

        const resultEl = document.getElementById('originalFruitResult');
        resultEl.innerHTML = `
            <div style="color: var(--ocean-blue); font-style: italic;">
                ✨ AI正在为你创造独特的果实能力...<br>
                <small>提示：将以下内容复制到prompt中让AI帮你完善设定</small>
            </div>
