    /* --- 生成逻辑 --- */
    function generateProfile() {
        if(usedPoints > maxPoints) {
            alert(`你的野心太大了！能力值总和不能超过天命上限 (${maxPoints})。请削弱一些属性。`);
            return;
        }

        const name = document.getElementById('charName').value || "无名海贼";
