        const birthplace = document.getElementById('birthplace').value;
        const faction = document.getElementById('faction').value;
        const bounty = parseInt(document.getElementById('bounty').value) || 0;

        const fruitMode = document.getElementById('fruitMode').value;
        let fruitInfo = "无";

        if(fruitMode === 'random' && selectedFruit) {
            fruitInfo = `${selectedFruit.type}·${selectedFruit.name} - ${selectedFruit.desc}`;
        } else if(fruitMode === 'custom') {
            const customName = document.getElementById('customFruitName').value;
            const customType = document.getElementById('customFruitType').value;
            const customDesc = document.getElementById('customFruitDesc').value;
            fruitInfo = `${customType}·${customName} - ${customDesc}`;
        } else if(fruitMode === 'original' && selectedFruit) {
